table-container {
    overflow-x: auto;
    margin-top: 2rem;
    border-radius: 8px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.1);
}

.products-table {
    width: 100%;
    border-collapse: collapse;
    background: var(--surface);
}

.products-table thead {
    background: var(--accent);
    color: white;
}

.products-table th {
    padding: 1rem;
    text-align: left;
    font-weight: 600;
    border-bottom: 2px solid var(--border);
}

.products-table td {
    padding: 1rem;
    border-bottom: 1px solid var(--border);
    vertical-align: middle;
}

.products-table tbody tr:hover {
    background: var(--border);
}

.products-table .img-cell {
    width: 60px;
}

.product-thumb {
    width: 50px;
    height: 40px;
    object-fit: cover;
    border-radius: 4px;
}

.color-cell {
    width: 60px;
    text-align: center;
}

.color-swatch {
    width: 40px;
    height: 40px;
    border-radius: 4px;
    border: 2px solid var(--border);
    display: inline-block;
}

.inventory-cell {
    font-size: 0.9rem;
    color: var(--text-secondary);
}

.actions-cell {
    width: 150px;
    display: flex;
    gap: 0.5rem;
}

.btn-sm {
    padding: 0.4rem 0.8rem;
    font-size: 0.85rem;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    display: inline-flex;
    align-items: center;
    gap: 0.3rem;
    transition: all 0.2s ease;
}

.btn-info {
    background: var(--accent);
    color: white;
}

.btn-warning {
    background: #ff9800;
    color: white;
}

.btn-danger {
    background: #f44336;
    color: white;
}

.btn-sm:hover {
    opacity: 0.8;
    transform: scale(1.05);
}

@media (max-width: 768px) {
    .products-table-container {
        font-size: 0.85rem;
    }

    .products-table th,
    .products-table td {
        padding: 0.5rem;
    }

    .product-thumb {
        width: 40px;
        height: 30px;
    }

    .color-swatch {
        width: 30px;
        height: 30px;
