{% block title %}{% if store %}Editar Almacén{% else %}Crear Almacén{% endif %} - FIWARE{% endblock %}

{% block content %}
<div class="container">
    <div class="form-container">
        <h1>{% if store %}Editar Almacén{% else %}Nuevo Almacén{% endif %}</h1>

        {% if error %}
        <div class="alert alert-error">{{ error }}</div>
        {% endif %}

        <form id="store-form" method="POST" action="{% if store %}/api/stores/{{ store.id.value }}{% else %}/api/stores{% endif %}">
            <fieldset>
                <legend>Información del Almacén</legend>

                <div class="form-group">
                    <label for="id">ID (único):</label>
                    <input type="text" id="id" name="id" required pattern="[a-z0-9\-]+" maxlength="50"
                           value="{% if store %}{{ store.id.value.split(':')[-1] }}{% endif %}" 
                           {% if store %}readonly{% endif %}
                           placeholder="ej: store-madrid-centro">
                    <small>Letras minúsculas, números y guiones. Sin espacios.</small>
                </div>

                <div class="form-group">
                    <label for="name">Nombre:</label>
                    <input type="text" id="name" name="name" required minlength="2" maxlength="100"
                           value="{% if store %}{{ store.name.value }}{% endif %}"
                           placeholder="ej: Almacén Madrid Centro">
                </div>

                <div class="form-group">
                    <label for="url">Sitio Web:</label>
                    <input type="url" id="url" name="url"
                           value="{% if store %}{{ store.url.value }}{% endif %}"
                           placeholder="https://ejemplo.com">
                </div>

                <div class="form-group">
                    <label for="telephone">Teléfono:</label>
                    <input type="tel" id="telephone" name="telephone" pattern="^[+]?[0-9\s\-()]{7,}$"
                           value="{% if store %}{{ store.telephone.value }}{% endif %}"
                           placeholder="+34 91 234 5678">
                    <small>Formato internacional: +34 91 234 5678</small>
                </div>

                <div class="form-group">
                    <label for="countryCode">País:</label>
                    <select id="countryCode" name="countryCode" required>
                        <option value="">-- Selecciona país --</option>
                        <option value="ES" {% if store and store.address and store.address.value and store.address.value.addressCountry == 'ES' %}selected{% endif %}>España (ES)</option>
                        <option value="FR" {% if store and store.address and store.address.value and store.address.value.addressCountry == 'FR' %}selected{% endif %}>Francia (FR)</option>
                        <option value="IT" {% if store and store.address and store.address.value and store.address.value.addressCountry == 'IT' %}selected{% endif %}>Italia (IT)</option>
                        <option value="PT" {% if store and store.address and store.address.value and store.address.value.addressCountry == 'PT' %}selected{% endif %}>Portugal (PT)</option>
                        <option value="DE" {% if store and store.address and store.address.value and store.address.value.addressCountry == 'DE' %}selected{% endif %}>Alemania (DE)</option>
                        <option value="GB" {% if store and store.address and store.address.value and store.address.value.addressCountry == 'GB' %}selected{% endif %}>Reino Unido (GB)</option>
                    </select>
                </div>

                <div class="form-group">
                    <label for="capacity">Capacidad (m²):</label>
                    <input type="number" id="capacity" name="capacity" required min="1" max="10000" step="1"
                           value="{% if store %}{{ store.capacity.value }}{% endif %}"
                           placeholder="ej: 500">
                </div>
            </fieldset>

            <fieldset>
                <legend>Dirección</legend>

                <div class="form-group">
                    <label for="addressLocality">Localidad:</label>
                    <input type="text" id="addressLocality" name="addressLocality" minlength="2" maxlength="100"
                           value="{% if store and store.address and store.address.value %}{{ store.address.value.addressLocality }}{% endif %}"
                           placeholder="ej: Madrid">
                </div>

                <div class="form-group">
                    <label for="addressStreet">Calle (opcional):</label>
                    <input type="text" id="addressStreet" name="addressStreet" maxlength="150"
                           value="{% if store and store.address and store.address.value %}{{ store.address.value.addressStreet }}{% endif %}"
                           placeholder="ej: Calle Principal 123">
                </div>
            </fieldset>

            <fieldset>
                <legend>Descripción e Imagen</legend>

                <div class="form-group">
                    <label for="description">Descripción:</label>
                    <textarea id="description" name="description" minlength="5" maxlength="500" rows="4"
                              placeholder="Descripción detallada del almacén">{% if store %}{{ store.description.value }}{% endif %}</textarea>
                </div>

                <div class="form-group">
                    <label for="image">URL de Imagen:</label>
                    <input type="url" id="image" name="image"
                           value="{% if store %}{{ store.image.value }}{% endif %}"
                           placeholder="https://ejemplo.com/imagen.jpg">
                </div>
            </fieldset>

            <div class="form-actions">
                <button type="submit" class="btn btn-primary">
                    {% if store %}Guardar Cambios{% else %}Crear Almacén{% endif %}
                </button>
                <a href="/stores" class="btn btn-secondary">Cancelar</a>
            </div>
        </form>
    </div>
</div>
{% endblock %}

