{% block content %}
<div class="container">
    <div class="form-container">
        <h1>{% if employee %}Editar Empleado{% else %}Nuevo Empleado{% endif %}</h1>

        {% if error %}
        <div class="alert alert-error">{{ error }}</div>
        {% endif %}

        <form id="employee-form" method="POST" action="{% if employee %}/api/employees/{{ employee.id.value }}{% else %}/api/employees{% endif %}">
            <fieldset>
                <legend>Información Personal</legend>

                <div class="form-group">
                    <label for="id">ID (único):</label>
                    <input type="text" id="id" name="id" required pattern="[a-z0-9\-]+" maxlength="50"
                           value="{% if employee %}{{ employee.id.value.split(':')[-1] }}{% endif %}" 
                           {% if employee %}readonly{% endif %}
                           placeholder="ej: emp-001">
                    <small>Letras minúsculas, números y guiones.</small>
                </div>

                <div class="form-group">
                    <label for="name">Nombre Completo:</label>
                    <input type="text" id="name" name="name" required minlength="2" maxlength="100"
                           value="{% if employee %}{{ employee.name.value }}{% endif %}"
                           placeholder="ej: Juan García López">
                </div>

                <div class="form-group">
                    <label for="email">Correo Electrónico:</label>
                    <input type="email" id="email" name="email" required maxlength="100"
                           value="{% if employee %}{{ employee.email.value }}{% endif %}"
                           placeholder="ej: juan@ejemplo.com">
                    <small>Será validado como único en el sistema.</small>
                </div>

                <div class="form-group">
                    <label for="dateOfContract">Fecha de Contratación:</label>
                    <input type="date" id="dateOfContract" name="dateOfContract" required
                           value="{% if employee %}{{ employee.dateOfContract.value.split('T')[0] if 'T' in employee.dateOfContract.value else employee.dateOfContract.value }}{% endif %}"
                           max="{% now 'Y-m-d' %}">
                </div>
            </fieldset>

            <fieldset>
                <legend>Credenciales</legend>

                <div class="form-group">
                    <label for="username">Nombre de Usuario:</label>
                    <input type="text" id="username" name="username" required minlength="4" maxlength="50"
                           value="{% if employee %}{{ employee.username.value }}{% endif %}"
                           placeholder="ej: juan.garcia"
                           {% if not employee %} autocomplete="off" {% endif %}>
                    <small>Será validado como único. Mínimo 4 caracteres.</small>
                </div>

                {% if not employee %}
                <div class="form-group">
                    <label for="password">Contraseña:</label>
                    <input type="password" id="password" name="password" required minlength="8" 
                           placeholder="Mínimo 8 caracteres (mayúscula, número, símbolo)"
                           autocomplete="new-password">
                    <div class="password-strength">
                        <div class="strength-meter" id="strength-meter"></div>
                    </div>
