                        <option value="Assistant" {% if employee and employee.category and employee.category.value == 'Assistant' %}selected{% endif %}>Asistente</option>
                        <option value="Operator" {% if employee and employee.category and employee.category.value == 'Operator' %}selected{% endif %}>Operario</option>
                        <option value="Supervisor" {% if employee and employee.category and employee.category.value == 'Supervisor' %}selected{% endif %}>Supervisor</option>
                    </select>
                </div>

                <div class="form-group">
                    <label>Competencias:</label>
                    <div class="checkbox-group">
                        <label class="checkbox-label">
                            <input type="checkbox" name="skills" value="MachineryDriving"
                                   {% if employee and employee.skills and 'MachineryDriving' in employee.skills.value %}checked{% endif %}>
                            <i class="fas fa-gears"></i> Conducción de Maquinaria
                        </label>
                        <label class="checkbox-label">
                            <input type="checkbox" name="skills" value="WritingReports"
                                   {% if employee and employee.skills and 'WritingReports' in employee.skills.value %}checked{% endif %}>
                            <i class="fas fa-file-text"></i> Redacción de Informes
                        </label>
                        <label class="checkbox-label">
                            <input type="checkbox" name="skills" value="CustomerRelationships"
                                   {% if employee and employee.skills and 'CustomerRelationships' in employee.skills.value %}checked{% endif %}>
